application-docker.yml:
spring:
  datasource:
    url: ${SPRING_DATASOURCE_URL:jdbc:postgresql://db:5432/privod_next}
    username: ${SPRING_DATASOURCE_USERNAME:privod}
    password: ${SPRING_DATASOURCE_PASSWORD:privod_secret}
  data:
    redis:
      host: ${SPRING_DATA_REDIS_HOST:redis}
      port: ${SPRING_DATA_REDIS_PORT:6379}

logging:
  level:
    com.privod: INFO
    org.hibernate.SQL: WARN
